def validate(args, output):
    n = args[0]
    connections = args[1]
    if not isinstance(output, list):
        return False
    # recompute the true bridge set with Tarjan low-link
    from collections import defaultdict
    adj = defaultdict(list)
    edgeset = set()
    for a, b in connections:
        adj[a].append(b)
        adj[b].append(a)
        edgeset.add(frozenset((a, b)))
    disc = [-1] * n
    low = [0] * n
    bridges = set()
    timer = [0]
    import sys
    sys.setrecursionlimit(300000)
    def dfs(u, parent_edge):
        disc[u] = low[u] = timer[0]
        timer[0] += 1
        for v in adj[u]:
            e = frozenset((u, v))
            if disc[v] == -1:
                dfs(v, e)
                low[u] = min(low[u], low[v])
                if low[v] > disc[u]:
                    bridges.add(frozenset((u, v)))
            elif e != parent_edge:
                low[u] = min(low[u], disc[v])
    for s in range(n):
        if disc[s] == -1:
            dfs(s, None)
    # validate output: each entry is a real edge, no duplicates, exactly the bridge set
    got = set()
    for item in output:
        if not isinstance(item, list) or len(item) != 2:
            return False
        key = frozenset((item[0], item[1]))
        if key not in edgeset:
            return False
        if key in got:
            return False
        got.add(key)
    return got == bridges

