function validate(args, output) {
    const n = args[0];
    const connections = args[1];
    if (!Array.isArray(output)) return false;
    const adj = Array.from({length: n}, () => []);
    const edgeset = new Set();
    const ekey = (a, b) => a < b ? a + ',' + b : b + ',' + a;
    for (const [a, b] of connections) {
        adj[a].push(b);
        adj[b].push(a);
        edgeset.add(ekey(a, b));
    }
    const disc = new Array(n).fill(-1);
    const low = new Array(n).fill(0);
    const bridges = new Set();
    let timer = 0;
    // iterative DFS to avoid recursion limits
    for (let start = 0; start < n; start++) {
        if (disc[start] !== -1) continue;
        const stack = [[start, -1, 0]];
        while (stack.length) {
            const frame = stack[stack.length - 1];
            const [u, parent, idx] = frame;
            if (idx === 0) {
                disc[u] = low[u] = timer++;
            }
            if (idx < adj[u].length) {
                frame[2]++;
                const v = adj[u][idx];
                if (v === parent) continue;
                if (disc[v] === -1) {
                    stack.push([v, u, 0]);
                } else {
                    low[u] = Math.min(low[u], disc[v]);
                }
            } else {
                stack.pop();
                if (parent !== -1) {
                    low[parent] = Math.min(low[parent], low[u]);
                    if (low[u] > disc[parent]) bridges.add(ekey(parent, u));
                }
            }
        }
    }
    const got = new Set();
    for (const item of output) {
        if (!Array.isArray(item) || item.length !== 2) return false;
        const key = ekey(item[0], item[1]);
        if (!edgeset.has(key)) return false;
        if (got.has(key)) return false;
        got.add(key);
    }
    if (got.size !== bridges.size) return false;
    for (const k of got) if (!bridges.has(k)) return false;
    return true;
}

