class Solution:
    def criticalConnections(self, n, connections):
        # brute force: an edge is critical iff removing it disconnects its endpoints
        from collections import defaultdict, deque
        full = defaultdict(set)
        for a, b in connections:
            full[a].add(b)
            full[b].add(a)
        def connected(skip_a, skip_b):
            start = skip_a
            seen = {start}
            q = deque([start])
            while q:
                u = q.popleft()
                for v in full[u]:
                    if (u == skip_a and v == skip_b) or (u == skip_b and v == skip_a):
                        continue
                    if v not in seen:
                        seen.add(v)
                        q.append(v)
            return skip_b in seen
        res = []
        for a, b in connections:
            if not connected(a, b):
                res.append([min(a, b), max(a, b)])
        res.sort()
        return res

